import { createFileRoute, getRouteApi } from "@tanstack/react-router"
import { CompetitionLocationCard } from "@/components/competition-location-card"
import { CompetitionTabs } from "@/components/competition-tabs"
import { CompetitionWorkoutCard } from "@/components/competition-workout-card"
import { EventDetailsContent } from "@/components/event-details-content"
import { RegistrationSidebar } from "@/components/registration-sidebar"
import {
	getPublicScheduleDataFn,
	type PublicScheduleEvent,
} from "@/server-fns/competition-heats-fns"
import {
	getBatchWorkoutDivisionDescriptionsFn,
	getPublishedCompetitionWorkoutsWithDetailsFn,
	type DivisionDescription,
} from "@/server-fns/competition-workouts-fns"
import { useDeferredSchedule } from "@/utils/use-deferred-schedule"

const parentRoute = getRouteApi("/compete/$slug")

export const Route = createFileRoute("/compete/$slug/")({
	component: CompetitionOverviewPage,
	loader: async ({ parentMatchPromise }) => {
		const parentMatch = await parentMatchPromise
		const competition = parentMatch.loaderData?.competition
		const divisions = parentMatch.loaderData?.divisions

		if (!competition) {
			return {
				workouts: [],
				divisionDescriptionsMap: {},
				deferredSchedule: Promise.resolve({
					events: [] as PublicScheduleEvent[],
				}),
			}
		}

		const competitionId = competition.id

		// Defer schedule data - it's below the fold and not needed immediately
		const deferredSchedule = getPublicScheduleDataFn({
			data: { competitionId },
		})

		const workoutsResult = await getPublishedCompetitionWorkoutsWithDetailsFn({
			data: { competitionId },
		})

		const workouts = workoutsResult.workouts
		const divisionIds = divisions?.map((d) => d.id) ?? []
		const divisionDescriptionsMap: Record<string, DivisionDescription[]> = {}

		if (divisionIds.length > 0 && workouts.length > 0) {
			const workoutIds = workouts.map((w) => w.workoutId)
			const batchResult = await getBatchWorkoutDivisionDescriptionsFn({
				data: { workoutIds, divisionIds },
			})
			Object.assign(divisionDescriptionsMap, batchResult.descriptionsByWorkout)
		}

		return { workouts, divisionDescriptionsMap, deferredSchedule }
	},
})

function CompetitionOverviewPage() {
	const {
		competition,
		userRegistration,
		isVolunteer,
		registrationStatus,
		session,
		divisions,
		sponsors,
		userDivision,
		userDivisions,
		maxSpots,
		organizerContactEmail,
	} = parentRoute.useLoaderData()

	const { slug } = Route.useParams()
	const { workouts, divisionDescriptionsMap, deferredSchedule } =
		Route.useLoaderData()

	const isRegistered = !!userRegistration
	const isTeamRegistration = (userDivision?.teamSize ?? 1) > 1
	const timezone = competition.timezone ?? "America/Denver"
	const scheduleMap = useDeferredSchedule({ deferredSchedule, timezone })

	return (
		<div className="grid gap-6 lg:grid-cols-[1fr_320px]">
			{/* Main Content Column */}
			<div className="space-y-4">
				{/* Sticky Tabs */}
				<div className="sticky top-4 z-10">
					<CompetitionTabs slug={competition.slug} />
				</div>

				{/* Content Panel */}
				<div className="rounded-2xl border border-black/10 bg-black/5 p-4 sm:p-6 backdrop-blur-md dark:border-white/10 dark:bg-white/5">
					<EventDetailsContent
						competition={competition}
						divisions={divisions.length > 0 ? divisions : undefined}
						sponsors={sponsors}
						workoutsContent={
							workouts.length > 0 ? (
								<div className="space-y-6">
									<h2 className="text-xl font-semibold mb-4">Workouts</h2>
									<div className="space-y-6">
										{workouts.map((event) => {
											const divisionDescriptionsResult =
												divisionDescriptionsMap[event.workoutId]
											return (
												<CompetitionWorkoutCard
													key={event.id}
													eventId={event.id}
													slug={slug}
													trackOrder={event.trackOrder}
													name={event.workout.name}
													scheme={event.workout.scheme}
													description={event.workout.description}
													roundsToScore={event.workout.roundsToScore}
													pointsMultiplier={event.pointsMultiplier}
													movements={event.workout.movements}
													tags={event.workout.tags}
													divisionDescriptions={
														divisionDescriptionsResult ?? []
													}
													sponsorName={event.sponsorName}
													sponsorLogoUrl={event.sponsorLogoUrl}
													selectedDivisionId="default"
													timeCap={event.workout.timeCap}
													schedule={scheduleMap?.get(event.id) ?? null}
												/>
											)
										})}
									</div>
								</div>
							) : undefined
						}
					/>
				</div>
			</div>

			{/* Sidebar - Order first on mobile/tablet for prominent Register button */}
			<aside className="order-first space-y-4 lg:order-none lg:sticky lg:top-4 lg:self-start">
				<RegistrationSidebar
					competition={competition}
					isRegistered={isRegistered}
					registrationOpen={registrationStatus.registrationOpen}
					maxSpots={maxSpots}
					userDivision={userDivision?.label}
					registrationId={userRegistration?.id}
					isTeamRegistration={isTeamRegistration}
					isCaptain={userRegistration?.userId === session?.userId}
					isVolunteer={isVolunteer}
					organizerContactEmail={organizerContactEmail}
					userRegistrations={userDivisions}
					session={session}
				/>
				<CompetitionLocationCard
					address={competition.address}
					competitionType={competition.competitionType}
					organizingTeamName={competition.organizingTeam?.name}
				/>
			</aside>
		</div>
	)
}

import { createFileRoute, notFound, useNavigate } from "@tanstack/react-router"
import { createServerFn } from "@tanstack/react-start"
import {
	Calendar,
	Clock,
	Dumbbell,
	ExternalLink,
	FileText,
	Filter,
	Link as LinkIcon,
	MapPin,
	Target,
	Timer,
	Trophy,
} from "lucide-react"
import { z } from "zod"
import { VideoSubmissionForm } from "@/components/compete/video-submission-form"
import { EventHeatSchedule } from "@/components/event-heat-schedule"
import { CompetitionTabs } from "@/components/competition-tabs"
import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import {
	Select,
	SelectContent,
	SelectItem,
	SelectTrigger,
	SelectValue,
} from "@/components/ui/select"
import { Separator } from "@/components/ui/separator"
import { getUserCompetitionRegistrationFn } from "@/server-fns/competition-detail-fns"
import {
	getPublicEventHeatsFn,
	getVenueForTrackWorkoutByDivisionFn,
} from "@/server-fns/competition-heats-fns"
import {
	getPublicEventDetailsFn,
	getWorkoutDivisionDescriptionsFn,
} from "@/server-fns/competition-workouts-fns"
import { getEventJudgingSheetsFn } from "@/server-fns/judging-sheet-fns"
import { getVideoSubmissionFn } from "@/server-fns/video-submission-fns"
import { getGoogleMapsUrl, hasAddressData } from "@/utils/address"
import { getSessionFromCookie } from "@/utils/auth"

const eventSearchSchema = z.object({
	division: z.string().optional(),
})

// Server function to get athlete's registered division for this competition
const getAthleteRegisteredDivisionFn = createServerFn({ method: "GET" })
	.inputValidator((data: unknown) =>
		z.object({ competitionId: z.string() }).parse(data),
	)
	.handler(async ({ data }) => {
		const session = await getSessionFromCookie()
		if (!session?.user?.id) {
			return { divisionId: null }
		}

		const result = await getUserCompetitionRegistrationFn({
			data: { competitionId: data.competitionId, userId: session.user.id },
		})

		return { divisionId: result.registration?.divisionId ?? null }
	})

export const Route = createFileRoute("/compete/$slug/workouts/$eventId")({
	component: EventDetailsPage,
	validateSearch: (search) => eventSearchSchema.parse(search),
	loader: async ({ params, parentMatchPromise }) => {
		const { eventId } = params

		const parentMatch = await parentMatchPromise
		const competition = parentMatch.loaderData?.competition
		const parentDivisions = parentMatch.loaderData?.divisions

		if (!competition) {
			throw notFound()
		}

		// Fetch event details, judging sheets, athlete's division, and video submission in parallel
		const [
			eventResult,
			judgingSheetsResult,
			athleteDivisionResult,
			videoSubmissionResult,
		] = await Promise.all([
			getPublicEventDetailsFn({
				data: { eventId, competitionId: competition.id },
			}),
			getEventJudgingSheetsFn({ data: { trackWorkoutId: eventId } }),
			getAthleteRegisteredDivisionFn({
				data: { competitionId: competition.id },
			}),
			// Only fetch video submission for online competitions
			competition.competitionType === "online"
				? getVideoSubmissionFn({
						data: { trackWorkoutId: eventId, competitionId: competition.id },
					})
				: Promise.resolve(null),
		])

		if (!eventResult.event) {
			throw notFound()
		}

		// Use divisions from parent
		const divisions = parentDivisions ?? []
		let divisionDescriptions: Array<{
			divisionId: string
			divisionLabel: string
			description: string | null
			position: number
		}> = []

		if (divisions.length > 0) {
			const descResult = await getWorkoutDivisionDescriptionsFn({
				data: {
					workoutId: eventResult.event.workoutId,
					divisionIds: divisions.map((d) => d.id),
				},
			})
			divisionDescriptions = descResult.descriptions
		}

		// Fetch venue for the first division (default)
		const defaultDivisionId = divisions.length > 0 ? divisions[0].id : null
		const venueResult = defaultDivisionId
			? await getVenueForTrackWorkoutByDivisionFn({
					data: { trackWorkoutId: eventId, divisionId: defaultDivisionId },
				})
			: { venue: null }

		// Defer heat schedule fetch - not needed for initial render
		const deferredEventHeats =
			eventResult.event.heatStatus === "published"
				? getPublicEventHeatsFn({ data: { trackWorkoutId: eventId } })
				: Promise.resolve({ heats: [] })

		return {
			competition,
			event: eventResult.event,
			resources: eventResult.resources,
			judgingSheets: judgingSheetsResult.sheets,
			heatTimes: eventResult.heatTimes,
			totalEvents: eventResult.totalEvents,
			divisionDescriptions,
			divisions,
			athleteRegisteredDivisionId: athleteDivisionResult.divisionId,
			venue: venueResult.venue,
			videoSubmission: videoSubmissionResult,
			deferredEventHeats,
		}
	},
})

function formatTime(seconds: number): string {
	const m = Math.floor(seconds / 60)
	const s = seconds % 60
	return `${m}:${s.toString().padStart(2, "0")}`
}

function getSchemeLabel(scheme: string, timeCap?: number | null): string {
	if (scheme === "time" || scheme === "time-with-cap") {
		return timeCap ? "For Time (Capped)" : "For Time"
	}
	if (scheme === "amrap") return "AMRAP"
	if (scheme === "emom") return "EMOM"
	if (scheme === "load") return "For Load"
	return scheme.replace(/-/g, " ").toUpperCase()
}

function formatHeatTime(date: Date, timezone?: string | null): string {
	return new Intl.DateTimeFormat("en-US", {
		weekday: "short",
		month: "short",
		day: "numeric",
		hour: "numeric",
		minute: "2-digit",
		timeZone: timezone ?? undefined,
	}).format(new Date(date))
}

function formatEventDateFromHeatTime(
	heatTime: Date,
	timezone?: string | null,
): string {
	return new Intl.DateTimeFormat("en-US", {
		month: "short",
		day: "numeric",
		year: "numeric",
		timeZone: timezone ?? undefined,
	}).format(new Date(heatTime))
}

function EventDetailsPage() {
	const {
		competition,
		event,
		resources,
		judgingSheets,
		heatTimes,
		totalEvents,
		divisionDescriptions,
		divisions,
		athleteRegisteredDivisionId,
		venue,
		videoSubmission,
		deferredEventHeats,
	} = Route.useLoaderData()
	const { slug } = Route.useParams()
	const search = Route.useSearch()
	const navigate = useNavigate({ from: Route.fullPath })

	const workout = event.workout
	const formattedTimeCap = workout.timeCap ? formatTime(workout.timeCap) : null
	const schemeLabel = getSchemeLabel(workout.scheme, workout.timeCap)

	// Sort division descriptions by position
	const sortedDivisions = [...divisionDescriptions].sort(
		(a, b) => a.position - b.position,
	)

	// Default to athlete's registered division, otherwise first division
	const defaultDivisionId =
		athleteRegisteredDivisionId ||
		(divisions && divisions.length > 0 ? divisions[0].id : undefined)
	const selectedDivisionId = search.division || defaultDivisionId

	// Get the selected division's scale info (separate from base description)
	const selectedDivision = sortedDivisions.find(
		(d) => d.divisionId === selectedDivisionId,
	)
	const divisionScale = selectedDivision?.description?.trim() || null
	const divisionLabel = selectedDivision?.divisionLabel || null

	const handleDivisionChange = (divisionId: string) => {
		navigate({
			search: (prev) => ({ ...prev, division: divisionId }),
			replace: true,
		})
	}

	return (
		<div className="grid gap-6 lg:grid-cols-[1fr_320px]">
			{/* Main Content */}
			<div className="space-y-4">
				{/* Competition Tabs */}
				<div className="sticky top-4 z-10">
					<CompetitionTabs slug={slug} />
				</div>

				{/* Glassmorphism Content Container */}
				<div className="rounded-2xl border border-black/10 bg-black/5 p-4 sm:p-6 backdrop-blur-md dark:border-white/10 dark:bg-white/5">
					<div className="space-y-8">
						{/* Header with Division Switcher */}
						<div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
							<div className="space-y-1">
								<div className="flex items-center gap-3">
									<Badge variant="outline" className="text-xs font-medium">
										Event {event.trackOrder} of {totalEvents}
									</Badge>
									{event.sponsorName && (
										<span className="text-xs text-muted-foreground">
											Presented by{" "}
											<span className="font-medium">{event.sponsorName}</span>
										</span>
									)}
								</div>
								<h1 className="text-2xl font-bold tracking-tight">
									{workout.name}
								</h1>
							</div>

							{divisions && divisions.length > 0 && (
								<div className="flex items-center gap-2">
									<Filter className="h-4 w-4 text-muted-foreground hidden sm:block" />
									<Select
										value={selectedDivisionId}
										onValueChange={handleDivisionChange}
									>
										<SelectTrigger className="w-full sm:w-[240px] h-10 font-medium">
											<SelectValue placeholder="Select Division" />
										</SelectTrigger>
										<SelectContent>
											{divisions.map((division) => (
												<SelectItem
													key={division.id}
													value={division.id}
													className="cursor-pointer"
												>
													{division.label}
												</SelectItem>
											))}
										</SelectContent>
									</Select>
								</div>
							)}
						</div>

						{/* Event Description */}
						<div className="space-y-4">
							{/* Base workout description */}
							<div className="font-mono text-sm whitespace-pre-wrap leading-relaxed">
								{workout.description || "Details coming soon."}
							</div>

							{/* Division-specific scale info */}
							{divisionScale && (
								<div className="border-t pt-4 mt-4">
									<div className="flex items-start gap-3">
										<Badge
											variant="secondary"
											className="shrink-0 text-xs font-medium"
										>
											{divisionLabel || "Division"}
										</Badge>
										<p className="font-mono text-sm whitespace-pre-wrap leading-relaxed text-muted-foreground">
											{divisionScale}
										</p>
									</div>
								</div>
							)}
						</div>

						{/* Heat Schedule */}
						{event.heatStatus === "published" && (
							<EventHeatSchedule
								deferredHeats={deferredEventHeats}
								timezone={competition.timezone}
							/>
						)}

						{/* Video & Score Submission Form - Below description for online competitions */}
						{competition.competitionType === "online" && videoSubmission && (
							<VideoSubmissionForm
								trackWorkoutId={event.id}
								competitionId={competition.id}
								timezone={competition.timezone}
								initialData={videoSubmission}
							/>
						)}
					</div>
				</div>
			</div>

			{/* Sidebar */}
			<aside className="space-y-4 lg:sticky lg:top-4 lg:self-start">
				{/* Submission Info Card - For online competitions */}
				{competition.competitionType === "online" &&
					videoSubmission?.submissionWindow && (
						<Card>
							<CardHeader className="pb-3">
								<CardTitle className="text-lg">Submission Window</CardTitle>
							</CardHeader>
							<CardContent className="space-y-3">
								<div className="flex items-start gap-3">
									<Calendar className="h-4 w-4 text-muted-foreground mt-0.5" />
									<div>
										<p className="text-xs text-muted-foreground uppercase tracking-wider">
											Opens
										</p>
										<p className="font-medium text-sm">
											{formatHeatTime(
												new Date(videoSubmission.submissionWindow.opensAt),
												competition.timezone,
											)}
										</p>
									</div>
								</div>
								<div className="flex items-start gap-3">
									<Clock className="h-4 w-4 text-muted-foreground mt-0.5" />
									<div>
										<p className="text-xs text-muted-foreground uppercase tracking-wider">
											Closes
										</p>
										<p className="font-medium text-sm">
											{formatHeatTime(
												new Date(videoSubmission.submissionWindow.closesAt),
												competition.timezone,
											)}
										</p>
									</div>
								</div>
								{videoSubmission.canSubmit ? (
									<p className="text-xs text-green-600 dark:text-green-400 font-medium">
										Submission window is open
									</p>
								) : (
									<p className="text-xs text-muted-foreground">
										{videoSubmission.reason}
									</p>
								)}
							</CardContent>
						</Card>
					)}

				{/* Event Info Card - Metadata */}
				<Card>
					<CardContent className="pt-6 space-y-4">
						{/* Workout Type */}
						<div className="flex items-start gap-3">
							<Target className="h-4 w-4 text-muted-foreground mt-0.5" />
							<div>
								<p className="text-xs text-muted-foreground uppercase tracking-wider">
									Format
								</p>
								<p className="font-medium text-sm">{schemeLabel}</p>
							</div>
						</div>

						{/* Time Cap */}
						{formattedTimeCap && (
							<div className="flex items-start gap-3">
								<Timer className="h-4 w-4 text-muted-foreground mt-0.5" />
								<div>
									<p className="text-xs text-muted-foreground uppercase tracking-wider">
										Time Cap
									</p>
									<p className="font-medium text-sm">{formattedTimeCap}</p>
								</div>
							</div>
						)}

						{/* Movements */}
						{workout.movements && workout.movements.length > 0 && (
							<div className="flex items-start gap-3">
								<Dumbbell className="h-4 w-4 text-muted-foreground mt-0.5" />
								<div>
									<p className="text-xs text-muted-foreground uppercase tracking-wider">
										Movements
									</p>
									<p className="font-medium text-sm">
										{workout.movements
											.map((m: { id: string; name: string }) => m.name)
											.join(", ")}
									</p>
								</div>
							</div>
						)}

						{heatTimes && (
							<div className="flex items-start gap-3">
								<Calendar className="h-4 w-4 text-muted-foreground mt-0.5" />
								<div>
									<p className="text-xs text-muted-foreground uppercase tracking-wider">
										Date
									</p>
									<p className="font-medium text-sm">
										{formatEventDateFromHeatTime(
											heatTimes.firstHeatStartTime,
											competition.timezone,
										)}
									</p>
								</div>
							</div>
						)}

						{event.pointsMultiplier && event.pointsMultiplier !== 100 && (
							<div className="flex items-start gap-3">
								<Trophy className="h-4 w-4 text-muted-foreground mt-0.5" />
								<div>
									<p className="text-xs text-muted-foreground uppercase tracking-wider">
										Points Multiplier
									</p>
									<p className="font-medium text-sm">
										{event.pointsMultiplier / 100}x
									</p>
								</div>
							</div>
						)}
					</CardContent>
				</Card>

				{/* Schedule Card */}
				{heatTimes && (
					<Card>
						<CardHeader className="pb-3">
							<CardTitle className="text-lg">Schedule</CardTitle>
						</CardHeader>
						<CardContent className="space-y-4">
							<div className="space-y-3">
								<div className="flex items-start gap-3">
									<Clock className="h-4 w-4 text-muted-foreground mt-0.5" />
									<div>
										<p className="text-xs text-muted-foreground uppercase tracking-wider">
											First Heat Starts
										</p>
										<p className="font-medium text-sm">
											{formatHeatTime(
												heatTimes.firstHeatStartTime,
												competition.timezone,
											)}
										</p>
									</div>
								</div>
								{heatTimes.firstHeatStartTime.getTime() !==
									heatTimes.lastHeatEndTime.getTime() && (
									<div className="flex items-start gap-3">
										<Clock className="h-4 w-4 text-muted-foreground mt-0.5" />
										<div>
											<p className="text-xs text-muted-foreground uppercase tracking-wider">
												Last Heat Ends
											</p>
											<p className="font-medium text-sm">
												{formatHeatTime(
													heatTimes.lastHeatEndTime,
													competition.timezone,
												)}
											</p>
										</div>
									</div>
								)}
							</div>
							<Separator />
							<p className="text-xs text-muted-foreground">
								Timezone: {competition.timezone}
							</p>
						</CardContent>
					</Card>
				)}

				{/* Venue Card */}
				<Card>
					<CardHeader className="pb-3">
						<CardTitle className="text-lg">Venue</CardTitle>
					</CardHeader>
					<CardContent>
						{venue?.address && hasAddressData(venue.address) ? (
							<div className="space-y-3">
								<div className="flex items-start gap-3">
									<MapPin className="h-4 w-4 text-muted-foreground mt-0.5" />
									<div className="flex-1">
										<p className="font-medium text-sm">{venue.name}</p>
										<p className="text-sm text-muted-foreground mt-1">
											{venue.address.streetLine1}
											{venue.address.streetLine2 && (
												<>
													<br />
													{venue.address.streetLine2}
												</>
											)}
											{(venue.address.city ||
												venue.address.stateProvince ||
												venue.address.postalCode) && (
												<>
													<br />
													{[venue.address.city, venue.address.stateProvince]
														.filter(Boolean)
														.join(", ")}{" "}
													{venue.address.postalCode}
												</>
											)}
											{venue.address.countryCode &&
												venue.address.countryCode !== "US" && (
													<>
														<br />
														{venue.address.countryCode}
													</>
												)}
										</p>
									</div>
								</div>
								<Button variant="outline" size="sm" className="w-full" asChild>
									<a
										href={getGoogleMapsUrl(venue.address) ?? undefined}
										target="_blank"
										rel="noopener noreferrer"
									>
										<MapPin className="h-4 w-4 mr-2" />
										Get Directions
									</a>
								</Button>
							</div>
						) : (
							<div className="flex items-start gap-3">
								<MapPin className="h-4 w-4 text-muted-foreground mt-0.5" />
								<p className="text-sm text-muted-foreground">
									Venue to be announced
								</p>
							</div>
						)}
					</CardContent>
				</Card>

				{/* Event Resources Card */}
				{resources && resources.length > 0 && (
					<Card>
						<CardHeader className="pb-3">
							<CardTitle className="text-lg">Event Resources</CardTitle>
						</CardHeader>
						<CardContent>
							<ul className="space-y-3">
								{resources.map((resource) => (
									<li key={resource.id}>
										{resource.url ? (
											<a
												href={resource.url}
												target="_blank"
												rel="noopener noreferrer"
												className="flex items-center gap-3 text-sm hover:text-primary transition-colors group"
											>
												<LinkIcon className="h-4 w-4 text-muted-foreground group-hover:text-primary" />
												<span className="flex-1">{resource.title}</span>
												<ExternalLink className="h-3 w-3 text-muted-foreground" />
											</a>
										) : (
											<div className="flex items-center gap-3 text-sm">
												<FileText className="h-4 w-4 text-muted-foreground" />
												<span className="flex-1">{resource.title}</span>
											</div>
										)}
									</li>
								))}
							</ul>
						</CardContent>
					</Card>
				)}

				{/* Judge Sheets Card */}
				{judgingSheets && judgingSheets.length > 0 && (
					<Card>
						<CardHeader className="pb-3">
							<CardTitle className="text-lg">Judge Sheets</CardTitle>
						</CardHeader>
						<CardContent>
							<ul className="space-y-3">
								{judgingSheets.map((sheet) => (
									<li key={sheet.id}>
										<a
											href={sheet.url}
											target="_blank"
											rel="noopener noreferrer"
											className="flex items-center gap-3 text-sm hover:text-primary transition-colors group"
										>
											<FileText className="h-4 w-4 text-muted-foreground group-hover:text-primary" />
											<span className="flex-1">{sheet.title}</span>
											<ExternalLink className="h-3 w-3 text-muted-foreground" />
										</a>
									</li>
								))}
							</ul>
						</CardContent>
					</Card>
				)}
			</aside>
		</div>
	)
}

