					>
						{/* Description - Takes up majority */}
						<div
							className={cn(
								hasMovementsOrTags ? "md:col-span-8" : "col-span-1",
							)}
						>
							<div className="prose prose-sm max-w-none dark:prose-invert space-y-4">
